code = """import json
import pandas as pd

# Function to count days with high volatility
def count_high_volatility_days(data_file):
    if isinstance(data_file, str):
        with open(data_file, 'r') as f:
            data = json.load(f)
    else:
        data = data_file
    
    if not data or len(data) == 0:
        return 0
    
    df = pd.DataFrame(data)
    df['High'] = pd.to_numeric(df['High'])
    df['Low'] = pd.to_numeric(df['Low'])
    
    # Calculate if range exceeds 20% of low
    df['Range_Exceeds_20pct'] = (df['High'] - df['Low']) > (df['Low'] * 0.20)
    
    return df['Range_Exceeds_20pct'].sum()

# Load company info
ticker_file = locals()['var_functions.query_db:34']
if isinstance(ticker_file, str):
    with open(ticker_file, 'r') as f:
        capital_market_tickers = json.load(f)
else:
    capital_market_tickers = ticker_file

# Create company mapping
symbol_to_company = {t['Symbol']: t['Company Description'] for t in capital_market_tickers}

# Process some tickers with the data we already have
results = []

# Process AGMH
agmh_file = locals()['var_functions.query_db:18']
agmh_days = count_high_volatility_days(agmh_file)
results.append({'symbol': 'AGMH', 'days': agmh_days, 'company': symbol_to_company['AGMH'][:100]})

# Process ALACU
alacu_file = locals()['var_functions.query_db:38']
alacu_days = count_high_volatility_days(alacu_file)
results.append({'symbol': 'ALACU', 'days': alacu_days, 'company': symbol_to_company['ALACU'][:100]})

# Process APEX
apex_file = locals()['var_functions.query_db:44']
apex_days = count_high_volatility_days(apex_file)
results.append({'symbol': 'APEX', 'days': apex_days, 'company': symbol_to_company['APEX'][:100]})

# Process BCLI
bcli_file = locals()['var_functions.query_db:48']
bcli_days = count_high_volatility_days(bcli_file)
results.append({'symbol': 'BCLI', 'days': bcli_days, 'company': symbol_to_company['BCLI'][:100]})

# Process BIOC
bioc_file = locals()['var_functions.query_db:49']
bioc_days = count_high_volatility_days(bioc_file)
results.append({'symbol': 'BIOC', 'days': bioc_days, 'company': symbol_to_company['BIOC'][:100]})

# Process BLFS
blfs_file = locals()['var_functions.query_db:50']
blfs_days = count_high_volatility_days(blfs_file)
results.append({'symbol': 'BLFS', 'days': blfs_days, 'company': symbol_to_company['BLFS'][:100]})

# Sort by days
top_results = sorted(results, key=lambda x: x['days'], reverse=True)

print('__RESULT__:')
print(json.dumps(top_results, indent=2))"""

